(ROOT/f'output/daily_blog_report_{DATE}.md').write_text('# ShopLovaNest Daily Blog Report - 2026-06-27\n\nStatus: generated; validation/deploy/email pending.\n\n' + '\n'.join(f'- {a["title"]}: https://shoplovanest.com/blog/{a["slug"]}/' for a in articles) + '\n', encoding='utf-8')
print('generated', ', '.join(a['slug'] for a in articles))
